from zipfile import ZipFile
from lxml import etree
import re, json, statistics
fn='/app/migration.xlsx'
NS={'a':'http://schemas.openxmlformats.org/spreadsheetml/2006/main'}

def colrow(ref):
    m=re.match(r'([A-Z]+)([0-9]+)',ref)
    col=0
    for ch in m.group(1):
        col=col*26+ord(ch)-64
    return col,int(m.group(2))

with ZipFile(fn) as z:
    ss=[]
    root=etree.fromstring(z.read('xl/sharedStrings.xml'))
    for si in root.findall('a:si',NS):
        ss.append(''.join((t.text or '') for t in si.findall('.//a:t',NS)))
    root=etree.fromstring(z.read('xl/worksheets/sheet1.xml'))  # 2023
    rows=[]
    for row in root.findall('.//a:sheetData/a:row',NS):
        vals={}
        for c in row.findall('a:c',NS):
            col,_=colrow(c.get('r'))
            v=c.find('a:v',NS)
            val=None
            if v is not None:
                txt=v.text
                if c.get('t')=='s':
                    val=ss[int(txt)]
                else:
                    try:
                        val=float(txt) if '.' in txt else int(txt)
                    except Exception:
                        val=txt
            vals[col]=val
        if vals:
            rows.append(vals)

